import pyotp
import qrcode

# Generate TOTP secret for user
totp = pyotp.TOTP(pyotp.random_base32())
secret = totp.secret

# Create QR code for authenticator app
uri = totp.provisioning_uri(name='user@example.com', issuer_name='YourCompany')
qr = qrcode.QRCode(version=1, error_correction=qrcode.constants.ERROR_CORRECT_L, box_size=10, border=4)
qr.add_data(uri)
qr.make(fit=True)
qr_img = qr.make_image(fill_color="black", back_color="white")
qr_img.save('qr_code.png')

# Validate TOTP code
def validate_totp(secret, code):
    totp = pyotp.TOTP(secret)
    return totp.verify(code)

# Example usage
user_secret = secret
user_code = input("Enter TOTP code from authenticator app: ")
if validate_totp(user_secret, user_code):
    print("TOTP code is valid.")
else:
    print("TOTP code is invalid.")